#!/bin/bash\n\n# ChatHub Quick Setup Script\n# এই script ChatHub সেটআপ প্রক্রিয়া সহজ করে দেয়\n\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║              ChatHub - Quick Setup Script                     ║\"\necho \"║          WhatsApp/Telegram Style Messaging App               ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\necho \"\"\necho \"এই স্ক্রিপ্ট আপনার ChatHub অ্যাপ্লিকেশন সেটআপ করতে সাহায্য করবে।\"\necho \"\"\n\n# Step 1: Check Node.js\necho \"[1/5] Node.js ইনস্টলেশন চেক করছি...\"\nif ! command -v node &> /dev/null\nthen\n    echo \"⚠️  Node.js ইনস্টল নেই। https://nodejs.org থেকে ডাউনলোড করুন\"\n    exit 1\nfi\necho \"✅ Node.js ইনস্টল করা আছে\"\necho \"\"\n\n# Step 2: Check Git\necho \"[2/5] Git ইনস্টলেশন চেক করছি...\"\nif ! command -v git &> /dev/null\nthen\n    echo \"⚠️  Git ইনস্টল নেই। https://git-scm.com থেকে ডাউনলোড করুন\"\n    exit 1\nfi\necho \"✅ Git ইনস্টল করা আছে\"\necho \"\"\n\n# Step 3: Clone Repository\necho \"[3/5] Repository ডাউনলোড করছি...\"\nif [ -d \"personal-whatsapp\" ]; then\n    echo \"ℹ️  Folder ইতিমধ্যে বিদ্যমান\"\nelse\n    git clone https://github.com/55ashraful/personal-whatsapp.git\n    if [ $? -eq 0 ]; then\n        echo \"✅ Repository সফলভাবে ডাউনলোড হয়েছে\"\n    else\n        echo \"❌ Repository ডাউনলোড ব্যর্থ\"\n        exit 1\n    fi\nfi\ncd personal-whatsapp\necho \"\"\n\n# Step 4: Setup Local Server\necho \"[4/5] Local সার্ভার সেটআপ করছি...\"\necho \"কোনটি ব্যবহার করবেন?\"\necho \"  1) Python HTTP Server\"\necho \"  2) Node.js HTTP Server\"\necho \"  3) VS Code Live Server (ম্যানুয়াল)\"\nread -p \"পছন্দ করুন (1-3): \" server_choice\n\ncase $server_choice in\n    1)\n        echo \"Python সার্ভার চালু করছি...\"\n        echo \"Note: Ctrl+C দিয়ে বন্ধ করতে পারবেন\"\n        python3 -m http.server 8000\n        ;;\n    2)\n        echo \"Node.js সার্ভার চালু করছি...\"\n        echo \"প্রথমে http-server ইনস্টল করছি...\"\n        npm install -g http-server\n        http-server\n        ;;\n    3)\n        echo \"VS Code এ project খুলুন এবং Live Server শুরু করুন\"\n        code .\n        ;;\n    *)\n        echo \"অবৈধ পছন্দ\"\n        exit 1\n        ;;\nesac\n\necho \"\"\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║                  সেটআপ সম্পন্ন!                           ║\"\necho \"╠═══════════════════════════════════════════════════════════════╣\"\necho \"║  Browser খুলুন এবং এই ঠিকানায় যান:                        ║\"\necho \"║  👉 http://localhost:8000 অথবা http://localhost:3000        ║\"\necho \"║                                                               ║\"\necho \"║  পরবর্তী পদক্ষেপ:                                           ║\"\necho \"║  1. firebase.js এ Firebase config আপডেট করুন              ║\"\necho \"║  2. SETUP_GUIDE.md পড়ুন বিস্তারিত নির্দেশনার জন্য        ║\"\necho \"║  3. Test phone number দিয়ে login করুন                     ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\n